// Estructura para guardar los datos de la postulacion.
// Se le agrega el campo "done" que sirve como semaforo de
// tipo spin-lock para sincronizar al estudiante con el trabajo
// que lo selecciono.
typedef struct {
    Estudiante *est;
    double *ranking;
    volatile int done;     // OPEN cuando el estudiante fue asignado
} Postulacion;

PriQueue *priQueue[N];
int postulacionTrabajos[N];

// Un unico spin-lock global que protege todos los accesos a
// priQueue[i], postulacionTrabajos[i] y al campo trabajo_id del
// estudiante durante la fase de seleccion.  De este modo se evitan
// las condiciones de carrera del codigo original.
static volatile int g_lock = OPEN;

void iniciarPostulaciones(){
  for (int i = 0; i < N; i++) {
    priQueue[i] = makePriQueue();
    postulacionTrabajos[i] = -1;
  }
}

void destruirPostulaciones(){
    for (int i = 0; i < N; i++) {
        destroyPriQueue(priQueue[i]);
        priQueue[i] = NULL;
    }
}

void postularTrabajo(
          Estudiante *est, int *preferencias, double *rank) {
  // Se inicializa trabajo_id antes de cualquier escritura visible
  // para que cualquier observador concurrente lo vea en -1.
  est->trabajo_id = -1;

  Postulacion *post = malloc(sizeof(Postulacion));
  post->est = est;
  post->ranking = rank;
  post->done = CLOSED;

  // Se accede a las colas de prioridad y a postulacionTrabajos
  // bajo el spin-lock global para evitar data races.
  spinLock(&g_lock);
  for (int i = 0; i < N; i++) {
    if (postulacionTrabajos[i] == -1 && preferencias[i])
      priPut(priQueue[i], post, rank[i]);
  }
  spinUnlock((int *)&g_lock);

  // Espera activa hasta que cerrarPostulacion libere este semaforo.
  // spinLock provee la barrera de adquisicion (dmb sy en swapInt) que
  // sincroniza con el spinUnlock hecho por el trabajo que asigno al
  // estudiante, garantizando visibilidad de trabajo_id.
  spinLock((volatile int *)&post->done);
  spinUnlock((int *)&post->done);

  free(post);
}

int cerrarPostulacion(int i) {
  int student_id = -1;
  for (;;) {
    spinLock(&g_lock);
    if (postulacionTrabajos[i] != -1) {
      student_id = postulacionTrabajos[i];
      spinUnlock((int *)&g_lock);
      return student_id;
    }

    Postulacion *assigned = NULL;
    while (!emptyPriQueue(priQueue[i])) {
      Postulacion *ppost = priGet(priQueue[i]);
      if (ppost->est->trabajo_id == -1) {
        student_id = ppost->est->id;
        postulacionTrabajos[i] = student_id;
        ppost->est->trabajo_id = i;
        for (int j = 0; j < N; j++)
          priDel(priQueue[j], ppost);
        assigned = ppost;
        break;
      }
      // Si el postulante ya fue tomado por otro trabajo, se descarta
      // (priGet ya lo saco de la cola i; la limpieza de las demas colas
      // la hizo el trabajo que lo asigno).
    }

    spinUnlock((int *)&g_lock);

    if (assigned != NULL) {
      // Se libera el semaforo del estudiante (provee barrera de
      // liberacion para que el estudiante vea trabajo_id).
      // Se usa student_id ya leido, porque luego el estudiante
      // podria liberar la Postulacion.
      spinUnlock((int *)&assigned->done);
      return student_id;
    }

    // La cola esta vacia o todos los postulantes fueron ya tomados:
    // se vuelve a intentar.  Esto es una espera activa, pero los
    // estudiantes iran llenando las colas bajo g_lock, por lo que
    // no hay deadlock.
  }
}

